let devices = [];
let cycle = context.get("cycle") || 1;

for (let i = 0; i < 100; i++) {
    let deviceId = "device_" + i.toString().padStart(3, '0');
    let isMalicious = i < 20; // First 20 are malicious
    let behaviorType = "NORMAL";

    let requestRate, payloadSize, endpoints, errorCount, totalRequests, knownEndpoints, totalEndpoints;

    if (!isMalicious || cycle <= 3) {
        requestRate = Math.floor(Math.random() * (12 - 8 + 1)) + 8;
        knownEndpoints = Math.floor(Math.random() * (3 - 2 + 1)) + 2;
        totalEndpoints = knownEndpoints;
        endpoints = [];
        for (let e=0; e<knownEndpoints; e++) endpoints.push("/api/data/" + e);
        payloadSize = Math.floor(Math.random() * (220 - 180 + 1)) + 180;
        errorCount = Math.floor(Math.random() * 2);
        totalRequests = requestRate;
    } else {
        if (i < 7) {
            behaviorType = "DDOS_ATTACK";
            requestRate = Math.floor(Math.random() * (400 - 250 + 1)) + 250;
            payloadSize = Math.floor(Math.random() * (220 - 180 + 1)) + 180;
            knownEndpoints = 2;
            totalEndpoints = 2;
            endpoints = ["/api/data/0", "/api/data/1"];
            errorCount = Math.floor(Math.random() * (20 - 10 + 1)) + 10;
            totalRequests = requestRate;
        } else if (i < 14) {
            behaviorType = "DATA_EXFILTRATION_ATTACK";
            requestRate = Math.floor(Math.random() * (12 - 8 + 1)) + 8;
            payloadSize = Math.floor(Math.random() * (15000 - 8000 + 1)) + 8000;
            knownEndpoints = 2;
            let extra = Math.floor(Math.random() * (43 - 23 + 1)) + 23;
            totalEndpoints = knownEndpoints + extra;
            endpoints = ["/api/data/0", "/api/data/1"];
            for(let e=0; e<extra; e++) endpoints.push("/api/hidden/" + e);
            errorCount = Math.floor(Math.random() * 2);
            totalRequests = requestRate;
        } else {
            behaviorType = "SLOW_POISON_ATTACK";
            let driftFactor = Math.min(cycle - 3, 8);
            requestRate = Math.floor(Math.random() * (12 - 8 + 1)) + 8 + (driftFactor * 2);
            payloadSize = Math.floor(Math.random() * (220 - 180 + 1)) + 180 + (driftFactor * 50);
            knownEndpoints = 2;
            totalEndpoints = knownEndpoints + driftFactor;
            endpoints = ["/api/data/0", "/api/data/1"];
            for(let e=0; e<driftFactor; e++) endpoints.push("/api/poison/" + e);
            errorCount = Math.floor(Math.random() * 2) + (driftFactor * 1);
            totalRequests = requestRate;
        }
    }

    devices.push({
        device_id: deviceId,
        timestamp: new Date().toISOString(),
        request_rate: requestRate,
        known_endpoints: knownEndpoints,
        total_endpoints: totalEndpoints,
        payload_size: payloadSize,
        endpoints: endpoints,
        error_count: errorCount,
        total_requests: totalRequests,
        is_malicious: isMalicious,
        behavior_type: behaviorType,
        cycle: cycle
    });
}

context.set("cycle", cycle + 1);

msg.payload = devices;
return msg;
